#!/usr/bin/env python3
# -*- coding: utf-8 -*-

import re
import json

def read_files():
    """读取输入文件"""
    with open('/sessions/sweet-dazzling-allen/podcast-notes-workspace/input/transcript.txt', 'r', encoding='utf-8') as f:
        transcript = f.read()

    with open('/sessions/sweet-dazzling-allen/podcast-notes-workspace/input/headings.txt', 'r', encoding='utf-8') as f:
        headings_raw = f.read()

    with open('/sessions/sweet-dazzling-allen/podcast-notes-workspace/input/metadata.txt', 'r', encoding='utf-8') as f:
        metadata_raw = f.read()

    return transcript, headings_raw, metadata_raw

def parse_headings(headings_raw):
    """解析章节标题"""
    headings = []
    for line in headings_raw.strip().split('\n'):
        if line.strip():
            match = re.match(r'\((\d+):(\d+)\)\s+(.*)', line.strip())
            if match:
                minutes, seconds, title = match.groups()
                timestamp = f"{int(minutes):02d}:{seconds}"
                total_seconds = int(minutes) * 60 + int(seconds)
                headings.append({
                    'timestamp': timestamp,
                    'title': title,
                    'total_seconds': total_seconds
                })

    headings.sort(key=lambda x: x['total_seconds'])
    return headings

def parse_metadata(metadata_raw):
    """解析元数据"""
    metadata = {}
    for line in metadata_raw.strip().split('\n'):
        if '：' in line:
            key, value = line.split('：', 1)
            metadata[key.strip()] = value.strip()
    return metadata

def parse_transcript(transcript):
    """解析逐字稿为结构化数据"""
    segments = []
    lines = transcript.split('\n')

    i = 0
    while i < len(lines):
        line = lines[i].rstrip()

        # 检查说话人标记（以中文冒号结尾）
        if '：' in line:
            parts = line.split('：', 1)
            speaker = parts[0].strip()
            text_start = parts[1].strip() if len(parts) > 1 else ''

            # 检查是否是有效的说话人
            if speaker in ['Peter Yang', 'Alex', 'Romain']:
                # 收集后续文本（直到下一个说话人或时间戳）
                text_lines = [text_start] if text_start else []
                i += 1

                while i < len(lines):
                    next_line = lines[i].rstrip()

                    # 检查下一个说话人
                    if '：' in next_line:
                        next_parts = next_line.split('：', 1)
                        if next_parts[0].strip() in ['Peter Yang', 'Alex', 'Romain']:
                            break

                    # 检查时间戳
                    if re.match(r'^00:\d{2}:\d{2}$', next_line):
                        segments.append({
                            'speaker': speaker,
                            'text': ' '.join(text_lines).strip(),
                            'timestamp': next_line
                        })
                        text_lines = []
                        i += 1
                        break

                    # 检查说话人切换标记或广告
                    if next_line.strip() in ['>>', 'This episode is brought to you by Granola.']:
                        if text_lines and text_lines[0]:
                            segments.append({
                                'speaker': speaker,
                                'text': ' '.join(text_lines).strip(),
                                'timestamp': None
                            })
                        text_lines = []
                        if next_line.strip() == '>>':
                            i += 1
                            break
                        else:
                            # 广告部分，跳过
                            while i < len(lines) and not (
                                '：' in lines[i] and lines[i].split('：')[0].strip() in ['Peter Yang', 'Alex', 'Romain']
                            ):
                                i += 1
                            break

                    if next_line.strip():
                        text_lines.append(next_line)

                    i += 1

                # 保存最后一段
                if text_lines and text_lines[0]:
                    segments.append({
                        'speaker': speaker,
                        'text': ' '.join(text_lines).strip(),
                        'timestamp': None
                    })
            else:
                i += 1
        else:
            i += 1

    return segments

def time_to_seconds(timestamp):
    """将时间戳转换为秒数"""
    if not timestamp:
        return float('inf')
    match = re.match(r'(\d{2}):(\d{2}):(\d{2})', timestamp)
    if match:
        hours, minutes, seconds = match.groups()
        return int(hours) * 3600 + int(minutes) * 60 + int(seconds)
    return float('inf')

def assign_segments_to_sections(segments, headings):
    """将段落分配到章节"""
    # 为段落添加时间戳信息
    current_timestamp = None
    for seg in segments:
        if seg['timestamp']:
            current_timestamp = seg['timestamp']
        seg['time_seconds'] = time_to_seconds(current_timestamp)

    # 为每个章节分配段落
    sections = []
    for i, heading in enumerate(headings):
        section_segments = []
        next_section_time = headings[i+1]['total_seconds'] if i+1 < len(headings) else float('inf')

        for seg in segments:
            if heading['total_seconds'] <= seg['time_seconds'] < next_section_time:
                section_segments.append(seg)

        sections.append({
            'heading': heading,
            'segments': section_segments
        })

    return sections

def main():
    # 读取和解析
    transcript, headings_raw, metadata_raw = read_files()
    headings = parse_headings(headings_raw)
    metadata = parse_metadata(metadata_raw)
    segments = parse_transcript(transcript)

    print("=== 解析完成 ===")
    print(f"章节数: {len(headings)}")
    print(f"段落数: {len(segments)}")
    print(f"元数据: {metadata}")

    # 分配段落到章节
    sections = assign_segments_to_sections(segments, headings)

    print(f"\n=== 章节分配结果 ===")
    for i, section in enumerate(sections):
        print(f"第 {i+1} 章 [{section['heading']['timestamp']}] {section['heading']['title']}")
        print(f"  包含 {len(section['segments'])} 个段落")
        for seg in section['segments'][:3]:
            text_preview = seg['text'][:60]
            print(f"    - {seg['speaker']}: {text_preview}...")

    # 保存中间结果供进一步处理
    with open('/tmp/podcast_structure.json', 'w', encoding='utf-8') as f:
        json.dump({
            'metadata': metadata,
            'headings': headings,
            'sections': [
                {
                    'heading': s['heading'],
                    'segments': [
                        {
                            'speaker': seg['speaker'],
                            'text': seg['text'][:200] + '...' if len(seg['text']) > 200 else seg['text']
                        }
                        for seg in s['segments']
                    ]
                }
                for s in sections
            ]
        }, f, ensure_ascii=False, indent=2)

if __name__ == '__main__':
    main()
